/**
 * ============================================================
 * PROCESO: Consulta automatizada de procesos judiciales
 * ============================================================
 * 
 * OBJETIVO:
 * Automatizar la consulta por nombre en el portal de la Rama Judicial
 * y capturar el resultado, priorizando la descarga DOC O EN SU DEFECTO en CSV directamente
 * en memoria sin necesidad de guardar archivos.
 * 
 *  ENTRADA:
 * - nombre: String obtenido desde el input del flujo
 * 
 * SALIDA:
 * - nombre_consultado
 * - filas_encontradas
 * - tipo de descarga (DOC | CSV)
 * - contenido CSV (si disponible)
 * - estado del proceso
 * 
 * TECNOLOGÍA:
 * - Puppeteer (automatización de navegador)
 * ============================================================
 */

const nombre = $input.first().json.snippet;

const codigo = `
module.exports = async ({ page }) => {

  // ============================================================
  // 1. NAVEGACIÓN AL PORTAL
  // ============================================================
  await page.goto(
    'https://consultaprocesos.ramajudicial.gov.co/Procesos/NombreRazonSocial',
    { waitUntil: 'networkidle2', timeout: 30000 }
  );

  // Espera a que cargue el grupo de opciones (radio buttons)
  await page.waitForSelector('.v-input--radio-group', { timeout: 30000 });


  // ============================================================
  // 2. SELECCIÓN DE TIPO DE PERSONA
  // ============================================================

  // Selecciona el radio correspondiente (value="false")
  await page.evaluate(() => {
    const radios = document.querySelectorAll('input[type="radio"]');
    for (const r of radios) {
      if (r.getAttribute('value') === 'false') { 
        r.click(); 
        break; 
      }
    }
  });

  // Abre el dropdown de tipo de persona
  await page.evaluate(() => {
    const inputs = document.querySelectorAll('input[readonly]');
    if (inputs[0]) inputs[0].click();
  });

  // Selecciona "Natural" del menú desplegable
  await page.waitForSelector('.v-menu__content', { visible: true, timeout: 10000 });
  await page.evaluate(() => {
    const items = document.querySelectorAll('.v-menu__content .v-list-item');
    for (const item of items) {
      if (item.textContent.includes('Natural')) { 
        item.click(); 
        break; 
      }
    }
  });


  // ============================================================
  // 3. INGRESO DEL NOMBRE A CONSULTAR
  // ============================================================
  const inputNombre = await page.waitForSelector(
    'xpath///label[contains(text(),"* Nombre(s) Apellido o Razón Social")]/following::input[1]',
    { timeout: 10000 }
  );

  await inputNombre.focus();

  // Limpia el campo antes de escribir
  await inputNombre.evaluate(el => el.value = '');

  // Escribe el nombre recibido como entrada
  await inputNombre.type('${nombre}');


  // ============================================================
  // 4. EJECUCIÓN DE LA CONSULTA
  // ============================================================
  await page.evaluate(() => {
    const spans = document.querySelectorAll('button span');
    for (const span of spans) {
      if (span.textContent.trim() === 'Consultar') { 
        span.closest('button').click(); 
        break; 
      }
    }
  });

  // Manejo opcional de pantalla intermedia con botón "Volver"
  try {
    await page.waitForSelector('button span', { timeout: 5000 });
    await page.evaluate(() => {
      const spans = document.querySelectorAll('button span');
      for (const span of spans) {
        if (span.textContent.trim() === 'Volver') { 
          span.closest('button').click(); 
          break; 
        }
      }
    });
  } catch(e) {}


  // ============================================================
  // 5. PROCESAMIENTO DE RESULTADOS
  // ============================================================
  await page.waitForSelector('table tbody tr', { timeout: 30000 });

  const resultado = await page.evaluate(() => {
    const filas = document.querySelectorAll('table tbody tr');

    // Validación de resultados mínimos
    if (filas.length < 6) {
      return { error: 'No hay suficientes filas', filas: filas.length };
    }

    // Selecciona el botón de la fila 6
    const boton = filas[5].querySelector('td:nth-child(2) button');

    if (boton) { 
      boton.click(); 
      return { ok: true, filas: filas.length }; 
    }

    return { error: 'Botón no encontrado' };
  });

  // Si ocurre error, retornar inmediatamente
  if (resultado.error) return { data: resultado };

  await new Promise(r => setTimeout(r, 2000));


  // ============================================================
  // 6. INTERCEPCIÓN DE DESCARGA (CSV EN MEMORIA)
  // ============================================================
  let csvContenido = null;

  await page.setRequestInterception(true);

  // Permitir todas las solicitudes
  page.on('request', req => req.continue());

  // Capturar respuestas que contengan CSV
  page.on('response', async response => {
    const url = response.url();

    if (
      url.includes('csv') || 
      url.includes('CSV') || 
      url.includes('export') || 
      url.includes('download')
    ) {
      try {
        csvContenido = await response.text();
      } catch(e) {}
    }
  });


  // ============================================================
  // 7. INTENTO DE DESCARGA (DOC → CSV)
  // ============================================================

  // Intentar descargar DOC primero
  const docClickado = await page.evaluate(() => {
    const spans = document.querySelectorAll('span');
    for (const span of spans) {
      if (span.textContent.trim() === 'DOC') {
        const boton = span.closest('button');
        if (boton) { 
          boton.click(); 
          return true; 
        }
      }
    }
    return false;
  });

  let descarga = 'DOC';

  if (docClickado) {
    await new Promise(r => setTimeout(r, 2000));

    // Validar si el DOC no está disponible
    try {
      const modalTexto = await page.$eval('.v-dialog--active', el => el.textContent.toLowerCase());

      if (modalTexto.includes('no está disponible')) {

        // Cerrar modal
        await page.evaluate(() => {
          const spans = document.querySelectorAll('.v-dialog--active span');
          for (const span of spans) {
            if (span.textContent.trim() === 'Volver') { 
              span.closest('button').click(); 
              break; 
            }
          }
        });

        await page.waitForSelector('.v-dialog--active', { hidden: true, timeout: 10000 });

        // Fallback a CSV
        descarga = 'CSV';
      }
    } catch(e) {}

  } else {
    descarga = 'CSV';
  }


  // ============================================================
  // 8. DESCARGA Y CAPTURA DE CSV
  // ============================================================
  if (descarga === 'CSV') {

    // Reintenta hasta 3 veces encontrar el botón
    for (let i = 0; i < 3; i++) {

      const csvOk = await page.evaluate(() => {
        const spans = document.querySelectorAll('span');

        for (const span of spans) {
          if (span.textContent.trim() === 'Descargar CSV') {
            const boton = span.closest('button');

            // Validar que el botón esté visible
            if (boton && boton.offsetParent !== null) { 
              boton.click(); 
              return true; 
            }
          }
        }
        return false;
      });

      if (csvOk) { 
        await new Promise(r => setTimeout(r, 3000));
        break; 
      }

      await new Promise(r => setTimeout(r, 2000));
    }
  }


  // ============================================================
  // 9. RESPUESTA FINAL
  // ============================================================
  return {
    data: {
      nombre_consultado: '${nombre}',
      filas_encontradas: resultado.filas,
      descarga: descarga,
      csvContenido: csvContenido || 'No se pudo capturar el contenido',
      status: 'completado'
    }
  };
};
`;

return [{
  json: {
    code: codigo,
    context: {}
  }
}];

const data = JSON.parse($input.first().json.data);

// Detectar tipo de archivo (puedes ajustar esto según tu input)
const tipo = data.tipo || 'csv';

let buffer;
let fileName;
let mimeType;

// ============================================================
// CSV
// ============================================================
if (tipo === 'csv') {
  const csvLimpio = data.csvContenido.replace(/\u0000/g, '');

  fileName = `procesos_${data.nombre_consultado.replace(/ /g, '_')}.csv`;
  buffer = Buffer.from(csvLimpio, 'utf-8');
  mimeType = 'text/csv';
}

// ============================================================
// DOC / DOCX
// ============================================================
else if (tipo === 'doc' || tipo === 'docx') {
  // Aquí asumimos que viene en base64
  buffer = Buffer.from(data.fileBase64, 'base64');

  const extension = tipo === 'doc' ? 'doc' : 'docx';
  fileName = `procesos_${data.nombre_consultado.replace(/ /g, '_')}.${extension}`;

  mimeType = tipo === 'doc'
    ? 'application/msword'
    : 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
}

// ============================================================
// PREPARAR BINARIO
// ============================================================
const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  fileName,
  mimeType
);

return [{
  json: {
    nombre: data.nombre_consultado,
    fileName
  },
  binary: {
    attachment: binaryData
  }
}];
